+            });
+        self.server
+            .pubsub_shard_subs
+            .retain(|_, clients| {
+                clients.remove(&client_id);
+                !clients.is_empty()
+            });
+        self.server.pubsub_outbox.remove(&client_id);
+    }
+
+    fn pubsub_sub_count(&self) -> usize {
+        self.server.store.subscribed_channels.len()
+            + self.server.store.subscribed_patterns.len()
